document.getElementById('contact-form').addEventListener('submit', async function(event) {
  event.preventDefault();

  const form = event.target;
  const formData = new FormData(form);

  try {
    // Step 1: Execute reCAPTCHA v3 to get token (invisible, no user interaction)
    const token = await grecaptcha.execute('6Lf6VpQsAAAAAJsIFRfVwjpjJPm55Bjg2P-LKU1m', { action: 'submit' });
    
    // Step 2: Add the token to the form data (this is what Formspree expects)
    formData.append('g-recaptcha-response', token);

    // Debug: see what's being sent
    console.log('Form data with captcha:', Object.fromEntries(formData));
    console.log('job selections:', formData.getAll('job'));

    const response = await fetch('https://formspree.io/f/mbdzpenw', {
      method: 'POST',
      headers: { 'Accept': 'application/json' },
      body: formData  // FormData handles multipart automatically
    });

    if (response.ok) {
      document.getElementById('success-message').style.display = 'block';
      document.getElementById('error-message').style.display = 'none';
      form.reset();
      inputElements.forEach((inputElement) => {
        inputElement.value = "";
        inputElement.closest(".contact-form__field").classList.remove("contact-form__field--valid");
      });
      document.querySelector('.chosen-select')?.dispatchEvent(new Event('chosen:updated'));
      setTimeout(() => document.getElementById('success-message').style.display = 'none', 5000);
    } else {
      const data = await response.json();
      console.error('Formspree error:', response.status, data);
      let errMsg = 'Submission failed.';
      if (data.errors) {
        errMsg = data.errors.map(e => e.message || e.field).join('; ');
      }
      document.getElementById('error-message').textContent = errMsg;
      document.getElementById('error-message').style.display = 'block';
    }
  } catch (err) {
    console.error('Error (captcha or network):', err);
    document.getElementById('error-message').textContent = 'Error – check console (likely captcha issue).';
    document.getElementById('error-message').style.display = 'block';
  }
});


(function () {

  var doc = document.documentElement;
  var w = window;

  var prevScroll = w.scrollY || doc.scrollTop;
  var curScroll;
  var direction = 0;
  var prevDirection = 0;

  var header = document.getElementById('site-header');

  var checkScroll = function () {

    /*
    ** Find the direction of scroll
    ** 0 - initial, 1 - up, 2 - down
    */

    curScroll = w.scrollY || doc.scrollTop;
    if (curScroll > prevScroll) {
      //scrolled up
      direction = 2;
    }
    else if (curScroll < prevScroll) {
      //scrolled down
      direction = 1;
    }

    // Update header background based on scroll position
    if (curScroll > document.querySelector(".hero").offsetHeight - 50) {
      header.classList.add("header--active");
    } else {
      header.classList.remove("header--active");
    }

    if (curScroll > document.querySelector(".hero").offsetHeight) {
      header.classList.remove('hide');
      prevDirection = direction;
    }
    else if (curScroll < 100) {
      header.classList.remove('hide');
      prevDirection = direction;
    }
    else {
      header.classList.add('hide');
      prevDirection = direction;
    }

    if (direction !== prevDirection) {
      toggleHeader(direction, curScroll);
    }

    prevScroll = curScroll;
  };

  var toggleHeader = function (direction, curScroll) {
    // if (direction === 2 && curScroll < document.querySelector(".hero").offsetHeight) {

    //   //replace 52 with the height of your header in px

    //   header.classList.add('hide');
    //   prevDirection = direction;
    // }
    // else if (direction === 1) {
    //   header.classList.remove('hide');
    //   prevDirection = direction;
    // } 
  };

  window.addEventListener('scroll', checkScroll);

})();

