function setThemePreference() {
  var d = new Date();
  /*
  * The getHours() method returns the hour (from 0 to 23) of the specified date and time.
  * Early mornig = 0 - 6
  * Morning = 6 - 12
  * Evening = 12 - 18
  * Night = 18 - 23
  */
  var currentHour = d.getHours();

  if (currentHour >= 19 || currentHour <= 6) {
    document.body.setAttribute("class", "dark-mode")
  } else {
    document.body.setAttribute("class", "light_theme")
  }
}

document.addEventListener('DOMContentLoaded', function() {
    const textArray = ["developer?", "designer?", "creator?", "problem-solver?"];
    const element = document.getElementById("typewriter-text");
    let wordIndex = 0;
    let charIndex = 0;
    let isDeleting = false;

    function type() {
        const currentWord = textArray[wordIndex];
        
        if (isDeleting) {
            element.textContent = currentWord.substring(0, charIndex - 1);
            charIndex--;
        } else {
            element.textContent = currentWord.substring(0, charIndex + 1);
            charIndex++;
        }

        let typeSpeed = isDeleting ? 50 : 100; // Faster deleting, slower typing

        if (!isDeleting && charIndex === currentWord.length) {
            typeSpeed = 3000; // Pause at end of word
            isDeleting = true;
        } else if (isDeleting && charIndex === 0) {
            isDeleting = false;
            wordIndex = (wordIndex + 1) % textArray.length; // Move to next word
            typeSpeed = 500;
        }

        setTimeout(type, typeSpeed);
    }

    type();
});


